function sha256Hex(input){
  let msg;
  if (typeof input==='string') msg=new TextEncoder().encode(input);
  else if (input instanceof Uint8Array) msg=input;
  else if (typeof Buffer!=='undefined' && Buffer.isBuffer(input)) msg=new Uint8Array(input);
  else msg=new TextEncoder().encode(String(input));
  const K=new Uint32Array([0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2]);
  let h0=0x6a09e667,h1=0xbb67ae85,h2=0x3c6ef372,h3=0xa54ff53a,h4=0x510e527f,h5=0x9b05688c,h6=0x1f83d9ab,h7=0x5be0cd19;
  const l=msg.length;
  const bitLenHi=Math.floor(l/0x20000000)>>>0;
  const bitLenLo=(l<<3)>>>0;
  const withOne=l+1;
  const k=(56-(withOne%64)+64)%64;
  const total=withOne+k+8;
  const m=new Uint8Array(total); m.set(msg,0); m[l]=0x80;
  const dv=new DataView(m.buffer);
  dv.setUint32(total-8,bitLenHi); dv.setUint32(total-4,bitLenLo);
  const w=new Uint32Array(64);
  const rotr=(x,n)=>((x>>>n)|(x<<(32-n)))>>>0;
  for(let off=0;off<total;off+=64){
    for(let i=0;i<16;i++) w[i]=dv.getUint32(off+i*4);
    for(let i=16;i<64;i++){
      const s0=(rotr(w[i-15],7)^rotr(w[i-15],18)^(w[i-15]>>>3))>>>0;
      const s1=(rotr(w[i-2],17)^rotr(w[i-2],19)^(w[i-2]>>>10))>>>0;
      w[i]=(w[i-16]+s0+w[i-7]+s1)>>>0;
    }
    let a=h0,b=h1,c=h2,d=h3,e=h4,f=h5,g=h6,h=h7;
    for(let i=0;i<64;i++){
      const S1=(rotr(e,6)^rotr(e,11)^rotr(e,25))>>>0;
      const ch=((e&f)^((~e)&g))>>>0;
      const t1=(h+S1+ch+K[i]+w[i])>>>0;
      const S0=(rotr(a,2)^rotr(a,13)^rotr(a,22))>>>0;
      const maj=((a&b)^(a&c)^(b&c))>>>0;
      const t2=(S0+maj)>>>0;
      h=g;g=f;f=e;e=(d+t1)>>>0;d=c;c=b;b=a;a=(t1+t2)>>>0;
    }
    h0=(h0+a)>>>0;h1=(h1+b)>>>0;h2=(h2+c)>>>0;h3=(h3+d)>>>0;h4=(h4+e)>>>0;h5=(h5+f)>>>0;h6=(h6+g)>>>0;h7=(h7+h)>>>0;
  }
  const toHex=x=>('00000000'+(x>>>0).toString(16)).slice(-8);
  return toHex(h0)+toHex(h1)+toHex(h2)+toHex(h3)+toHex(h4)+toHex(h5)+toHex(h6)+toHex(h7);
}
// ========================================
// Parse request + decode JWT + validate input + tính hash
// ========================================
const headers = $('Webhook Ingest').first().json.headers || {};
const body = $('Webhook Ingest').first().json.body || {};

// --- Decode JWT để lấy user_id ---
const authHeader = headers.authorization || headers.Authorization || '';
const token = authHeader.replace('Bearer ', '');

if (!token) {
  return [{ json: { error: true, message: 'Thiếu token xác thực', status: 401 } }];
}

let userId = null;
try {
  const payload = JSON.parse(Buffer.from(token.split('.')[1], 'base64').toString());
  userId = payload.sub;
  if (!userId) throw new Error('Token không chứa user ID');
} catch (e) {
  return [{ json: { error: true, message: 'Token không hợp lệ: ' + e.message, status: 401 } }];
}

// --- Validate input ---
const required = ['document_code', 'document_title', 'file_content', 'file_name'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  return [{ json: { error: true, message: 'Thiếu trường bắt buộc: ' + missing.join(', '), status: 400 } }];
}

const validLangs = ['vi', 'en', 'vi-en', 'other'];
const langCode = body.language_code || 'vi';
if (!validLangs.includes(langCode)) {
  return [{ json: { error: true, message: 'language_code không hợp lệ', status: 400 } }];
}

// --- Tính SHA256 hash ---

const fileBuffer = Buffer.from(body.file_content, 'base64');
const fileHash = sha256Hex(fileBuffer);

return [{
  json: {
    error: false,
    user_id: userId,
    document_code: body.document_code,
    document_title: body.document_title,
    document_type: body.document_type || 'sop',
    language_code: langCode,
    source_type: body.source_type || 'internal_sop',
    version: body.version || '01',
    owner_department: body.owner_department || null,
    equipment_type: body.equipment_type || null,
    equipment_code: body.equipment_code || null,
    process_area: body.process_area || null,
    translation_of_document_id: body.translation_of_document_id || null,
    is_ai_translated: body.is_ai_translated || false,
    file_content: body.file_content,
    file_name: body.file_name,
    mime_type: body.mime_type || 'application/pdf',
    file_hash: fileHash,
    file_size_bytes: fileBuffer.length,
    document_group_id: (body.source_type || 'INTERNAL_SOP').toUpperCase() + '-' + body.document_code
  }
}];

// Kiểm tra quyền upload
const roles = $input.all().map(item => item.json.role_name);
const prevData = $('Parse + Validate + Hash').first().json;

const canUpload = roles.some(r => ['admin', 'qa_manager', 'validation'].includes(r));

if (roles.length === 0 || !canUpload) {
  return [{ json: { error: true, message: 'Bạn không có quyền upload tài liệu', status: 403 } }];
}

return [{ json: { ...prevData, user_roles: roles, primary_role: roles[0] } }];

// Kiểm tra kết quả duplicate
const dupResult = $input.first().json;
const prevData = $('Check Upload Permission').first().json;

if (dupResult && dupResult.is_duplicate === true) {
  return [{ json: {
    error: true, is_duplicate: true,
    message: 'Tài liệu trùng lặp (' + dupResult.match_type + '). ID: ' + dupResult.existing_document_id,
    status: 409
  }}];
}

return [{ json: { ...prevData, is_duplicate: false } }];

// ========================================
// Trích xuất text + page-aware chunking
// ========================================
const docRecord = $input.first().json;
const prevData = $('Process Dup Result').first().json;

const fileBuffer = Buffer.from(prevData.file_content, 'base64');
const text = fileBuffer.toString('utf-8');

// Page-aware chunking
const CHUNK_SIZE = 1500;
const CHUNK_OVERLAP = 200;

const pageBreaks = text.split(/\f|\n---\n|\n={3,}\n/);
let chunks = [];
let chunkIndex = 0;

for (let pageNum = 0; pageNum < pageBreaks.length; pageNum++) {
  const pageText = pageBreaks[pageNum].trim();
  if (!pageText) continue;

  const sectionMatch = pageText.match(/^(\d+\.\d*\.?\d*)\s+(.+?)$/m);
  const sectionCode = sectionMatch ? sectionMatch[1] : null;
  const sectionTitle = sectionMatch ? sectionMatch[2].trim() : null;

  if (pageText.length <= CHUNK_SIZE) {
    chunks.push({
      content: pageText,
      chunk_index: chunkIndex++,
      page_number: pageNum + 1,
      section_code: sectionCode,
      section_title: sectionTitle,
      chunk_type: 'text',
      content_tokens: Math.ceil(pageText.length / 3)
    });
  } else {
    let start = 0;
    while (start < pageText.length) {
      let end = Math.min(start + CHUNK_SIZE, pageText.length);
      if (end < pageText.length) {
        const bp = Math.max(pageText.lastIndexOf('.', end), pageText.lastIndexOf('\n', end));
        if (bp > start + CHUNK_SIZE * 0.5) end = bp + 1;
      }
      const ct = pageText.substring(start, end).trim();
      if (ct) {
        chunks.push({
          content: ct, chunk_index: chunkIndex++, page_number: pageNum + 1,
          section_code: sectionCode, section_title: sectionTitle,
          chunk_type: 'text', content_tokens: Math.ceil(ct.length / 3)
        });
      }
      start = end - CHUNK_OVERLAP;
    }
  }
}

// Chuẩn bị danh sách text cho OpenAI embedding
const textsForEmbedding = chunks.map(c => c.content);

return [{
  json: {
    document_id: docRecord.id,
    document_code: prevData.document_code,
    document_version: prevData.version,
    language_code: prevData.language_code,
    source_type: prevData.source_type,
    file_hash: prevData.file_hash,
    user_id: prevData.user_id,
    primary_role: prevData.primary_role,
    chunks: chunks,
    texts_for_embedding: textsForEmbedding,
    total_chunks: chunks.length,
    total_pages: pageBreaks.filter(p => p.trim()).length
  }
}];

// ========================================
// Ghép embedding vào chunks + tạo SQL INSERT
// ========================================
const embedResult = $input.first().json;
const prevData = $('Extract + Chunk').first().json;

const embeddings = embedResult.data || [];
const chunks = prevData.chunks;

// Tạo SQL INSERT cho tất cả chunks
let values = [];
for (let i = 0; i < chunks.length; i++) {
  const c = chunks[i];
  const emb = embeddings[i]?.embedding;
  const embStr = emb ? "'[" + emb.join(',') + "]'" : 'NULL';
  const content = c.content.replace(/'/g, "''"); // Escape single quotes
  const secCode = c.section_code ? "'" + c.section_code.replace(/'/g, "''") + "'" : 'NULL';
  const secTitle = c.section_title ? "'" + c.section_title.replace(/'/g, "''") + "'" : 'NULL';

  values.push(`('${prevData.document_id}', '${content}', ${c.content_tokens}, ${c.chunk_index}, ${c.page_number}, NULL, ${secCode}, ${secTitle}, '${c.chunk_type}', '${prevData.document_code}', '${prevData.document_version}', '${prevData.language_code}'::language_code, '${prevData.source_type}'::source_type, '${prevData.file_hash}', ${embStr}::vector, 'indexed'::document_status)`);
}

const insertSQL = `INSERT INTO document_chunks (document_id, content, content_tokens, chunk_index, page_number, page_range, section_code, section_title, chunk_type, document_code, document_version, language_code, source_type, file_hash, embedding, status) VALUES ${values.join(',\n')};`;

// SQL cập nhật status + audit log
const updateSQL = `UPDATE documents SET status = 'indexed', indexed_at = now(), chunk_count = ${chunks.length}, page_count = ${prevData.total_pages}, updated_at = now() WHERE id = '${prevData.document_id}'::uuid;`;

const auditSQL = `SELECT write_audit_log('${prevData.user_id}'::uuid, NULL, '${prevData.primary_role}', 'document_index'::audit_action, 'Upload + index: ${prevData.document_code}', NULL, NULL, '${prevData.document_id}'::uuid, '${prevData.document_code}', '${prevData.document_version}', '${prevData.language_code}'::language_code, '${prevData.file_hash}');`;

return [{ json: {
  sql: insertSQL + '\n' + updateSQL + '\n' + auditSQL,
  document_id: prevData.document_id,
  document_code: prevData.document_code,
  language_code: prevData.language_code,
  total_chunks: chunks.length,
  total_pages: prevData.total_pages
}}];
